import os
import json
import logging
from flask import Flask, request, jsonify
from kafka import KafkaProducer
from kafka.errors import NoBrokersAvailable, KafkaError

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

app = Flask(__name__)

# Kafka Producer configuration
# Use environment variable for Kafka brokers, default to localhost:9092
KAFKA_BROKERS = os.environ.get('KAFKA_BROKERS', 'localhost:9092').split(',')

producer = None

def get_kafka_producer():
    """
    Initializes and returns a KafkaProducer instance.
    Handles potential NoBrokersAvailable error during initialization.
    """
    global producer
    if producer is None:
        try:
            producer = KafkaProducer(
                bootstrap_servers=KAFKA_BROKERS,
                value_serializer=lambda v: json.dumps(v).encode('utf-8'),
                acks='all',  # Ensure all in-sync replicas have received the message
                retries=5,   # Retry sending messages up to 5 times
                linger_ms=10, # Wait up to 10ms for more messages to batch
                batch_size=16384 # Batch size of 16KB
            )
            logging.info(f"KafkaProducer initialized with brokers: {KAFKA_BROKERS}")
        except NoBrokersAvailable:
            logging.error(f"No Kafka brokers available at {KAFKA_BROKERS}. Producer could not be initialized.")
            producer = None # Ensure producer is None if initialization fails
        except KafkaError as e:
            logging.error(f"An unexpected Kafka error occurred during producer initialization: {e}")
            producer = None
    return producer

@app.route('/publish', methods=['POST'])
def publish_message():
    """
    Publishes a message to a Kafka topic specified in the request parameters.
    Expects 'topic' as a query parameter and 'message' in the JSON body.
    """
    topic = request.args.get('topic')
    if not topic:
        return jsonify({"error": "Topic name is required. Please provide it as a query parameter, e.g., /publish?topic=my_topic"}), 400

    try:
        message_data = request.get_json()
        if not message_data:
            return jsonify({"error": "Message body is required and must be valid JSON."}), 400
    except Exception as e:
        return jsonify({"error": f"Invalid JSON in request body: {e}"}), 400

    current_producer = get_kafka_producer()
    if current_producer is None:
        return jsonify({"error": "Kafka producer is not available. Please check Kafka broker connectivity."}), 503

    try:
        # As per requirement: producer.send(topic_name, message)
        future = current_producer.send(topic, message_data)
        record_metadata = future.get(timeout=10) # Block until send is complete, with a timeout

        logging.info(f"Successfully published message to topic '{record_metadata.topic}' "
                     f"partition {record_metadata.partition} offset {record_metadata.offset}")
        return jsonify({
            "status": "success",
            "message": "Message published",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset,
            "payload": message_data
        }), 200

    except KafkaError as e:
        logging.error(f"Failed to publish message to topic '{topic}': {e}")
        return jsonify({"error": f"Failed to publish message to Kafka: {e}"}), 500
    except Exception as e:
        logging.error(f"An unexpected error occurred: {e}")
        return jsonify({"error": f"An unexpected error occurred: {e}"}), 500

@app.route('/health', methods=['GET'])
def health_check():
    """
    Simple health check endpoint.
    """
    current_producer = get_kafka_producer()
    if current_producer is not None:
        # A more robust health check might try to list topics or send a test message
        # For now, just checking if the producer object exists.
        return jsonify({"status": "healthy", "kafka_producer_initialized": True}), 200
    else:
        return jsonify({"status": "unhealthy", "kafka_producer_initialized": False, "error": "Kafka producer not available"}), 503

if __name__ == '__main__':
    # Ensure producer is initialized on startup if possible
    get_kafka_producer()

    # Run the Flask app
    # Use environment variable for host and port, default to 0.0.0.0:5000
    HOST = os.environ.get('FLASK_HOST', '0.0.0.0')
    PORT = int(os.environ.get('FLASK_PORT', 5000))
    app.run(host=HOST, port=PORT)

# Graceful shutdown (optional, but good practice for long-running services)
@app.teardown_appcontext
def shutdown_producer(exception=None):
    global producer
    if producer is not None:
        logging.info("Closing Kafka producer...")
        producer.close()
        producer = None
        logging.info("Kafka producer closed.")